1	<!DOCTYPE html>
2	<!-- @dsCard group="Brand" name="Demo · Misma sesión en todos tus dispositivos" subtitle="Continuidad: portátil → escritorio, misma sesión" viewport="1000x560" -->
3	<html lang="es">
4	<head>
5	<meta charset="UTF-8" />
6	<meta name="viewport" content="width=device-width, initial-scale=1" />
7	<title>Terminal Sync · Misma sesión en todos tus dispositivos</title>
8	<link href="https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700&family=Geist+Mono:wght@400;500&display=swap" rel="stylesheet" />
9	<style>
10	  :root{
11	    --ink:#1d2127;--ink2:#5b616b;--ink3:#9aa0aa;--line:#e7e8ec;
12	    --indigo:#5b56e6;--claude:#d9774f;--claude-bg:#fdf6f1;--accent:#0f9d6e;
13	    --bezel:#1b1f26;--bezel2:#0d1014;
14	    --sans:'Geist',system-ui,sans-serif;--mono:'Geist Mono',ui-monospace,monospace;
15	  }
16	  *{box-sizing:border-box;}
17	  html,body{margin:0;height:100%;}
18	  body{font-family:var(--sans);color:var(--ink);background:
19	      radial-gradient(70% 60% at 50% 0%,#ffffff,transparent 70%),
20	      linear-gradient(180deg,#f7f5f1,#eef0ee);
21	    display:flex;flex-direction:column;align-items:center;justify-content:center;gap:22px;padding:28px 18px;min-height:100vh;-webkit-font-smoothing:antialiased;}
22	
23	  .scene{display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:clamp(10px,3vw,40px);width:100%;max-width:1000px;}
24	
25	  /* ---------- shared mini app screen ---------- */
26	  .screen-wrap{position:relative;width:100%;aspect-ratio:16/10;background:#fff;border-radius:6px;overflow:hidden;}
27	  .ts-mini{position:absolute;inset:0;display:flex;flex-direction:column;font-size:10px;background:#fff;}
28	  .mini-bar{display:flex;align-items:center;gap:7px;padding:8px 11px;border-bottom:1px solid var(--line);font-weight:600;font-size:10.5px;}
29	  .mini-bar .mb-dot{width:7px;height:7px;border-radius:50%;background:var(--claude);}
30	  .mini-bar .mb-sync{margin-left:auto;font-family:var(--mono);font-size:8.5px;color:var(--accent);font-weight:500;display:flex;align-items:center;gap:4px;}
31	  .mini-bar .mb-sync::before{content:"";width:5px;height:5px;border-radius:50%;background:var(--accent);}
32	  .mini-chat{flex:1;padding:11px;display:flex;flex-direction:column;gap:9px;overflow:hidden;}
33	  .mu{align-self:flex-end;background:var(--indigo);color:#fff;border-radius:9px;padding:7px 10px;max-width:78%;font-size:9.5px;line-height:1.4;}
34	  .mc{border:1px solid var(--line);border-left:3px solid var(--claude);background:var(--claude-bg);border-radius:8px;padding:9px 11px;}
35	  .mc-h{font-family:var(--mono);font-size:7.5px;font-weight:600;letter-spacing:.1em;color:#bf6438;display:flex;align-items:center;gap:5px;margin-bottom:6px;}
36	  .mc-h::before{content:"";width:6px;height:6px;border-radius:50%;background:var(--claude);}
37	  .mc b{font-size:11px;display:block;margin-bottom:7px;}
38	  .mc .ln{height:5px;border-radius:3px;background:#eadfd6;margin:5px 0;}
39	  .mc .ln.s{width:60%;} .mc .ln.m{width:85%;}
40	  .cursor{display:inline-block;width:5px;height:11px;background:var(--indigo);margin-left:1px;vertical-align:-1px;animation:bk 1s steps(1) infinite;}
41	  @keyframes bk{50%{opacity:0;}}
42	
43	  /* screen overlays (desktop) */
44	  .ov{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:12px;background:#06070a;color:#e8eaed;font-family:var(--mono);font-size:11px;z-index:2;}
45	  .ov.hide{display:none;}
46	  .spin{width:26px;height:26px;border-radius:50%;border:2.5px solid rgba(255,255,255,.18);border-top-color:var(--accent);animation:sp .8s linear infinite;}
47	  @keyframes sp{to{transform:rotate(360deg);}}
48	  .ov small{color:#9aa0aa;}
49	
50	  .badge-sync{position:absolute;top:9px;right:9px;background:var(--accent);color:#fff;font-family:var(--mono);font-size:8px;font-weight:600;padding:4px 8px;border-radius:999px;display:flex;align-items:center;gap:4px;opacity:0;transform:translateY(-4px);transition:opacity .4s,transform .4s;z-index:3;}
51	  .badge-sync.show{opacity:1;transform:none;}
52	  .badge-sync::before{content:"✓";}
53	
54	  /* ---------- devices ---------- */
55	  .device{display:flex;flex-direction:column;align-items:center;gap:0;transition:opacity .5s,filter .5s;}
56	  .dev-label{font-family:var(--mono);font-size:11px;color:var(--ink2);margin-top:14px;letter-spacing:.02em;}
57	  .dev-label b{color:var(--ink);font-weight:600;}
58	
59	  /* laptop */
60	  .laptop .lid{width:100%;max-width:360px;background:var(--bezel);border:6px solid var(--bezel);border-radius:12px 12px 0 0;padding:0;box-shadow:0 24px 50px -28px rgba(0,0,0,.5);}
61	  .laptop .lid .screen-wrap{border-radius:5px;}
62	  .laptop .base{width:calc(100% + 26px);max-width:386px;height:11px;background:linear-gradient(180deg,#c9ccd3,#a9adb6);border-radius:0 0 11px 11px;position:relative;}
63	  .laptop .base::after{content:"";position:absolute;top:0;left:50%;transform:translateX(-50%);width:64px;height:5px;background:#8b8f99;border-radius:0 0 7px 7px;}
64	  .laptop.dim .lid{filter:brightness(.45) saturate(.7);}
65	
66	  /* desktop monitor */
67	  .desktop .monitor{position:relative;width:100%;max-width:380px;background:var(--bezel);border:7px solid var(--bezel);border-radius:14px;box-shadow:0 26px 54px -28px rgba(0,0,0,.55);}
68	  .desktop .monitor .screen-wrap{border-radius:5px;background:#06070a;}
69	  .desktop .power{position:absolute;bottom:-3px;right:14px;width:8px;height:8px;border-radius:50%;background:#3a3f48;transition:background .4s,box-shadow .4s;}
70	  .desktop .power.on{background:var(--accent);box-shadow:0 0 10px var(--accent);}
71	  .desktop .stand{width:90px;height:34px;background:linear-gradient(180deg,#c9ccd3,#a9adb6);clip-path:polygon(30% 0,70% 0,100% 100%,0 100%);margin-top:-1px;}
72	  .desktop .stand-base{width:120px;height:7px;background:#a9adb6;border-radius:4px;margin-top:2px;}
73	
74	  /* sync link */
75	  .sync{display:flex;flex-direction:column;align-items:center;gap:10px;min-width:90px;}
76	  .cloud{display:flex;flex-direction:column;align-items:center;gap:5px;color:var(--ink2);}
77	  .cloud svg{width:34px;height:34px;stroke:var(--accent);stroke-width:1.6;fill:none;}
78	  .cloud span{font-family:var(--mono);font-size:9px;color:var(--accent);display:flex;align-items:center;gap:4px;}
79	  .track{position:relative;width:100%;height:2px;background:repeating-linear-gradient(90deg,var(--line) 0 5px,transparent 5px 10px);border-radius:2px;}
80	  .pulse{position:absolute;top:50%;left:0;width:9px;height:9px;border-radius:50%;background:var(--accent);box-shadow:0 0 10px var(--accent);transform:translate(-50%,-50%);opacity:0;}
81	  .pulse.go{animation:travel 1.6s ease forwards;}
82	  @keyframes travel{0%{left:0;opacity:0;}15%{opacity:1;}85%{opacity:1;}100%{left:100%;opacity:0;}}
83	
84	  .caption{font-size:clamp(15px,2.2vw,19px);font-weight:500;color:var(--ink);text-align:center;max-width:46ch;min-height:2.6em;display:flex;align-items:center;justify-content:center;transition:opacity .35s;letter-spacing:-0.01em;}
85	  .caption b{color:var(--accent);}
86	  .replay{display:none;}
87	  .replay:hover{}
88	  .replay svg{}
89	
90	  @media(max-width:640px){
91	    .scene{grid-template-columns:1fr;gap:8px;}
92	    .sync{flex-direction:row;width:60%;margin:6px auto;}
93	    .track{width:80px;} .cloud svg{width:26px;height:26px;}
94	    .desktop{order:3;}
95	  }
96	</style>
97	</head>
98	<body>
99	  <div class="scene" id="scene">
100	    <!-- LAPTOP -->
101	    <div class="device laptop" id="laptop">
102	      <div class="lid">
103	        <div class="screen-wrap">
104	          <div class="ts-mini">
105	            <div class="mini-bar"><span class="mb-dot"></span>Agencia · skincare<span class="mb-sync">Sincronizado</span></div>
106	            <div class="mini-chat">
107	              <div class="mu">Dame un plan de campaña de 90 días para el cliente de skincare<span class="cursor" id="cur"></span></div>
108	              <div class="mc"><div class="mc-h">CLAUDE</div><b>Plan de Campaña 90 días</b><div class="ln m"></div><div class="ln"></div><div class="ln s"></div></div>
109	            </div>
110	          </div>
111	        </div>
112	      </div>
113	      <div class="base"></div>
114	      <div class="dev-label"><b>Tu portátil</b> · en casa</div>
115	    </div>
116	
117	    <!-- SYNC -->
118	    <div class="sync">
119	      <div class="cloud">
120	        <svg viewBox="0 0 24 24"><path d="M17 18a4 4 0 0 0 .5-7.97A6 6 0 0 0 6 9a4.5 4.5 0 0 0 .5 9z"/><path d="M12 11v6"/><path d="m9.5 14.5 2.5 2.5 2.5-2.5"/></svg>
121	        <span>Tu nube · E2EE</span>
122	      </div>
123	      <div class="track"><div class="pulse" id="pulse"></div></div>
124	    </div>
125	
126	    <!-- DESKTOP -->
127	    <div class="device desktop" id="desktop">
128	      <div class="monitor">
129	        <div class="screen-wrap">
130	          <span class="badge-sync" id="badge">Al día</span>
131	          <div class="ts-mini" id="deskApp">
132	            <div class="mini-bar"><span class="mb-dot"></span>Agencia · skincare<span class="mb-sync">Sincronizado</span></div>
133	            <div class="mini-chat">
134	              <div class="mu">Dame un plan de campaña de 90 días para el cliente de skincare</div>
135	              <div class="mc"><div class="mc-h">CLAUDE</div><b>Plan de Campaña 90 días</b><div class="ln m"></div><div class="ln"></div><div class="ln s"></div></div>
136	            </div>
137	          </div>
138	          <div class="ov" id="ovOff"></div>
139	          <div class="ov hide" id="ovBoot"><div class="spin"></div><span>Sincronizando sesión…</span><small>Recuperando contexto y memoria</small></div>
140	        </div>
141	        <div class="power" id="power"></div>
142	      </div>
143	      <div class="stand"></div>
144	      <div class="stand-base"></div>
145	      <div class="dev-label"><b>Escritorio</b> · en la oficina</div>
146	    </div>
147	  </div>
148	
149	  <div class="caption" id="caption">En tu portátil, trabajando con tu IA.</div>
150	  <button class="replay" id="replay"><svg viewBox="0 0 24 24"><path d="M3 2v6h6"/><path d="M3 13a9 9 0 1 0 3-7.7L3 8"/></svg>Reproducir de nuevo</button>
151	
152	<script>
153	(function(){
154	  const lang=(new URLSearchParams(location.search).get('lang')==='en')?'en':'es';
155	  const _embed=new URLSearchParams(location.search).get('embed')==='1';
156	  document.documentElement.lang=lang;
157	
158	  const T={
159	    es:{
160	      sessionTitle:'Agencia · skincare',
161	      synced:'Sincronizado',
162	      userMsg:'Dame un plan de campaña de 90 días para el cliente de skincare',
163	      planTitle:'Plan de Campaña 90 días',
164	      laptopLabel:'Tu portátil · en casa',
165	      desktopLabel:'Escritorio · en la oficina',
166	      cloudLabel:'Tu nube · E2EE',
167	      badge:'Al día',
168	      booting:'Sincronizando sesión…',
169	      bootingSub:'Recuperando contexto y memoria',
170	      capInit:'En tu portátil, trabajando con tu IA.',
171	      cap1:'Cierras el portátil y te vas a la oficina.',
172	      cap2:'Enciendes el computador de la oficina…',
173	      cap3:'La&nbsp;<b>misma conversación</b>, justo donde la dejaste.',
174	    },
175	    en:{
176	      sessionTitle:'Agency · skincare',
177	      synced:'Synced',
178	      userMsg:'Give me a 90-day campaign plan for the skincare client',
179	      planTitle:'90-day Campaign Plan',
180	      laptopLabel:'Your laptop · at home',
181	      desktopLabel:'Desktop · at the office',
182	      cloudLabel:'Your cloud · E2EE',
183	      badge:'Up to date',
184	      booting:'Syncing session…',
185	      bootingSub:'Recovering context and memory',
186	      capInit:'On your laptop, working with your AI.',
187	      cap1:'You close the laptop and head to the office.',
188	      cap2:'You turn on the office computer…',
189	      cap3:'The&nbsp;<b>same conversation</b>, right where you left it.',
190	    }
191	  };
192	  const t=T[lang];
193	
194	  // Apply static translations to HTML
195	  document.querySelectorAll('.mini-bar').forEach(el=>{
196	    const sync=el.querySelector('.mb-sync');
197	    const dot=el.querySelector('.mb-dot');
198	    if(dot) el.innerHTML='';
199	    if(dot){el.appendChild(dot);}
200	    el.appendChild(document.createTextNode(t.sessionTitle));
201	    if(sync){sync.textContent=t.synced;el.appendChild(sync);}
202	  });
203	  document.querySelectorAll('.mu').forEach(el=>{
204	    const cur=el.querySelector('#cur');
205	    el.textContent=t.userMsg;
206	    if(cur)el.appendChild(cur);
207	  });
208	  document.querySelectorAll('.mc b').forEach(el=>{ el.textContent=t.planTitle; });
209	  const laptopLabel=document.querySelector('.laptop .dev-label');
210	  if(laptopLabel) laptopLabel.innerHTML='<b>'+t.laptopLabel.split(' · ')[0]+'</b> · '+t.laptopLabel.split(' · ')[1];
211	  const desktopLabel=document.querySelector('.desktop .dev-label');
212	  if(desktopLabel) desktopLabel.innerHTML='<b>'+t.desktopLabel.split(' · ')[0]+'</b> · '+t.desktopLabel.split(' · ')[1];
213	  const cloudSpan=document.querySelector('.cloud span');
214	  if(cloudSpan) cloudSpan.textContent=t.cloudLabel;
215	  document.getElementById('badge').textContent=t.badge;
216	  const ovBoot=document.getElementById('ovBoot');
217	  if(ovBoot){ ovBoot.querySelector('span').textContent=t.booting; ovBoot.querySelector('small').textContent=t.bootingSub; }
218	
219	  const laptop=document.getElementById('laptop');
220	  const desktop=document.getElementById('desktop');
221	  const power=document.getElementById('power');
222	  const ovOff=document.getElementById('ovOff');
223	  const badge=document.getElementById('badge');
224	  const pulse=document.getElementById('pulse');
225	  const cap=document.getElementById('caption');
226	  const cur=document.getElementById('cur');
227	  let timers=[];
228	  const at=(ms,fn)=>timers.push(setTimeout(fn,ms));
229	  function say(html){cap.style.opacity=0;setTimeout(()=>{cap.innerHTML=html;cap.style.opacity=1;},250);}
230	
231	  function reset(){
232	    timers.forEach(clearTimeout);timers=[];
233	    laptop.classList.remove('dim');
234	    power.classList.remove('on');
235	    ovOff.classList.remove('hide');
236	    ovBoot.classList.add('hide');
237	    badge.classList.remove('show');
238	    pulse.classList.remove('go');
239	    if(cur)cur.style.display='inline-block';
240	    cap.innerHTML=t.capInit;
241	    cap.style.opacity=1;
242	  }
243	
244	  function play(){
245	    reset();
246	    at(2200,()=>{ say(t.cap1); if(cur)cur.style.display='none'; laptop.classList.add('dim'); void pulse.offsetWidth; pulse.classList.add('go'); });
247	    at(4400,()=>{ say(t.cap2); power.classList.add('on'); ovOff.classList.add('hide'); ovBoot.classList.remove('hide'); });
248	    at(6600,()=>{ ovBoot.classList.add('hide'); });
249	    at(7000,()=>{ badge.classList.add('show'); say(t.cap3); });
250	  }
251	
252	  document.getElementById('replay').addEventListener('click',play);
253	
254	  let started=false;
255	  const io=new IntersectionObserver(es=>{es.forEach(e=>{if(e.isIntersecting&&!started){started=true;play();}});},{threshold:.35});
256	  io.observe(document.getElementById('scene'));
257	  reset();
258	})();
259	</script>
260	</body>
261	</html>
