1	<!DOCTYPE html>
2	<!-- @dsCard group="Ads" name="Ad · WhatsApp 15s" subtitle="¿Seguimos con otra IA? · ES/EN" viewport="1080x1920" -->
3	<html lang="es">
4	<head>
5	<meta charset="UTF-8" />
6	<meta name="viewport" content="width=device-width, initial-scale=1" />
7	<title>TerminalSync · Ad WhatsApp</title>
8	<link rel="preconnect" href="https://fonts.googleapis.com" />
9	<link href="https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700&display=swap" rel="stylesheet" />
10	<style>
11	  :root {
12	    --bg: #f7f5f1;
13	    --ink: #16181d;
14	    --ink2: #5b616b;
15	    --accent: #0f9d6e;
16	    --wa-bg: #e5ded5;
17	    --wa-bg-pattern: #ded3c2;
18	    --wa-header: #075e54;
19	    --wa-bubble-recv: #ffffff;
20	    --wa-bubble-sent: #d9fdd3;
21	  }
22	  * { box-sizing: border-box; -webkit-font-smoothing: antialiased; }
23	  html, body { margin: 0; padding: 0; }
24	  body {
25	    font-family: 'Geist', system-ui, sans-serif;
26	    color: var(--ink);
27	    background: #000;
28	    width: 1080px;
29	    height: 1920px;
30	    overflow: hidden;
31	    position: relative;
32	  }
33	  .stage { position: absolute; inset: 0; }
34	
35	  /* SCENE 1 — WhatsApp chat (0–12s) */
36	  .scene-chat {
37	    position: absolute; inset: 0;
38	    background: var(--wa-bg);
39	    background-image: radial-gradient(circle at 1px 1px, var(--wa-bg-pattern) 1.5px, transparent 0);
40	    background-size: 32px 32px;
41	    opacity: 1;
42	    transition: opacity 0.6s ease;
43	  }
44	  .scene-chat.hide { opacity: 0; pointer-events: none; }
45	
46	  /* WhatsApp header */
47	  .wa-header {
48	    height: 156px;
49	    background: var(--wa-header);
50	    padding: 60px 36px 0 36px;
51	    display: flex;
52	    align-items: center;
53	    gap: 22px;
54	    color: #fff;
55	  }
56	  .wa-avatar {
57	    width: 72px; height: 72px;
58	    border-radius: 50%;
59	    background: linear-gradient(135deg, #3b82f6, #0284c7);
60	    display: flex; align-items: center; justify-content: center;
61	    flex-shrink: 0;
62	    overflow: hidden;
63	  }
64	  .wa-avatar svg { width: 72px; height: 72px; display: block; }
65	  .wa-meta { display: flex; flex-direction: column; gap: 4px; }
66	  .wa-name { font-size: 30px; font-weight: 600; letter-spacing: -0.01em; }
67	  .wa-status { font-size: 19px; color: #c7e4df; font-weight: 400; }
68	
69	  /* Chat body */
70	  .chat {
71	    position: absolute;
72	    top: 156px; left: 0; right: 0; bottom: 0;
73	    padding: 60px 60px 60px;
74	    display: flex; flex-direction: column;
75	    gap: 36px;
76	  }
77	  .bubble {
78	    max-width: 78%;
79	    padding: 28px 34px;
80	    border-radius: 24px;
81	    font-size: 42px;
82	    line-height: 1.28;
83	    font-weight: 500;
84	    letter-spacing: -0.005em;
85	    box-shadow: 0 2px 6px rgba(0,0,0,0.08);
86	    opacity: 0;
87	    transform: translateY(40px) scale(0.96);
88	    transition: opacity 0.55s ease-out, transform 0.55s cubic-bezier(0.22,1.4,0.36,1);
89	  }
90	  .bubble.show { opacity: 1; transform: translateY(0) scale(1); }
91	  .bubble.recv {
92	    background: var(--wa-bubble-recv);
93	    align-self: flex-start;
94	    border-top-left-radius: 6px;
95	  }
96	  .bubble.sent {
97	    background: var(--wa-bubble-sent);
98	    align-self: flex-end;
99	    border-top-right-radius: 6px;
100	  }
101	  .bubble .ts {
102	    display: block;
103	    margin-top: 10px;
104	    font-size: 20px;
105	    color: var(--ink2);
106	    font-weight: 400;
107	    text-align: right;
108	  }
109	  .bubble.recv .ts { text-align: left; }
110	
111	  /* Work cards strip (8–12s) */
112	  .work-cards {
113	    position: absolute;
114	    left: 60px; right: 60px;
115	    bottom: 130px;
116	    display: flex;
117	    flex-direction: column;
118	    gap: 22px;
119	    opacity: 0;
120	    transition: opacity 0.5s ease;
121	  }
122	  .work-cards.show { opacity: 1; }
123	  .work-card {
124	    background: #fff;
125	    border-radius: 22px;
126	    padding: 26px 32px;
127	    display: flex;
128	    align-items: center;
129	    gap: 22px;
130	    box-shadow: 0 4px 14px rgba(0,0,0,0.07);
131	    opacity: 0;
132	    transform: translateX(40px);
133	    transition: opacity 0.5s ease-out, transform 0.5s cubic-bezier(0.22,1.2,0.36,1);
134	  }
135	  .work-card.show { opacity: 1; transform: translateX(0); }
136	  .work-check {
137	    width: 56px; height: 56px;
138	    border-radius: 50%;
139	    background: var(--accent);
140	    color: #fff;
141	    display: flex; align-items: center; justify-content: center;
142	    flex-shrink: 0;
143	  }
144	  .work-check svg { width: 32px; height: 32px; stroke: currentColor; stroke-width: 3; fill: none; stroke-linecap: round; stroke-linejoin: round; }
145	  .work-text {
146	    font-size: 34px;
147	    font-weight: 600;
148	    color: var(--ink);
149	    letter-spacing: -0.01em;
150	  }
151	
152	  /* SCENE 2 — Brand close (12–15s) */
153	  .scene-brand {
