103	async function tts(voiceId, text, outPath, attempt = 1) {
104	  const url = `https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`;
105	  const body = JSON.stringify({ text, model_id: MODEL, voice_settings: SETTINGS });
106	  const res = await fetch(url, {
107	    method: 'POST',
108	    headers: {
109	      'xi-api-key': API_KEY,
110	      'Content-Type': 'application/json',
111	      Accept: 'audio/mpeg',
112	    },
113	    body,
114	  });
115	  if (!res.ok) {
116	    const err = await res.text();
117	    if (attempt < 4 && (res.status === 429 || res.status >= 500)) {
118	      const delay = 1000 * Math.pow(2, attempt);
119	      console.log(`  ⏳ ${res.status} — retry ${attempt}/3 en ${delay}ms`);
120	      await new Promise((r) => setTimeout(r, delay));
121	      return tts(voiceId, text, outPath, attempt + 1);
122	    }
123	    throw new Error(`ElevenLabs ${res.status}: ${err}`);
124	  }
125	  const buf = Buffer.from(await res.arrayBuffer());
126	  fs.writeFileSync(outPath, buf);
127	  return buf.length;
128	}
