135	  for (const lang of langs) {
136	    const list = ADS[lang];
137	    if (!list) { console.error(`Lang desconocido: ${lang}`); continue; }
138	    const outDir = path.join('locucion-ads', lang);
139	    fs.mkdirSync(outDir, { recursive: true });
140	    console.log(`\n🎙️  Locución ${lang.toUpperCase()} → ${outDir}`);
141	    for (let i = 0; i < list.length; i++) {
142	      if (argAd && i + 1 !== argAd) continue;
143	      const [name, text] = list[i];
144	      const out = path.join(outDir, `${name}.mp3`);
145	      if (fs.existsSync(out) && fs.statSync(out).size > 5000) {
146	        console.log(`  ✓ ${name}.mp3 (ya existe, skip)`);
147	        continue;
148	      }
149	      process.stdout.write(`  · ${name}.mp3 ... `);
150	      try {
151	        const bytes = await tts(VOICES[lang], text, out);
152	        console.log(`OK (${Math.round(bytes / 1024)} KB)`);
153	      } catch (e) {
154	        console.log(`FAIL`);
155	        console.error(`    ${e.message}`);
156	      }
157	    }
158	  }
159	  console.log('\n✅ Listo. Locuciones en ./locucion-ads/');
160	}
