      '',
      "AIs stop.",
      "Your business doesn't.",
      'TerminalSync.',
    ].join(' ')],

    // 30s · NIVEL 1 ad ("You don't need to be a developer") — 6 clips.
    ['ad-03-equipo-l1', "You don't need to be a developer to work with AI."],
    ['ad-03-equipo-l2', 'Ask for a proposal. A campaign. An analysis.'],
    ['ad-03-equipo-l3', 'Claude thinks. Codex builds. Gemini analyzes.'],
    ['ad-03-equipo-l4', 'All from one place.'],
    ['ad-03-equipo-l5', 'And if one AI stops, another keeps the work going.'],
    ['ad-03-equipo-l6', 'TerminalSync. Your AIs producing. You directing. From any device.'],
  ],
};

async function tts(voiceId, text, outPath, attempt = 1) {
  const url = `https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`;
  const body = JSON.stringify({ text, model_id: MODEL, voice_settings: SETTINGS });
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'xi-api-key': API_KEY,
      'Content-Type': 'application/json',
      Accept: 'audio/mpeg',
    },
    body,
  });
  if (!res.ok) {
    const err = await res.text();
    if (attempt < 4 && (res.status === 429 || res.status >= 500)) {
      const delay = 1000 * Math.pow(2, attempt);
      console.log(`  ⏳ ${res.status} — retry ${attempt}/3 en ${delay}ms`);
      await new Promise((r) => setTimeout(r, delay));
      return tts(voiceId, text, outPath, attempt + 1);
    }
    throw new Error(`ElevenLabs ${res.status}: ${err}`);
  }
  const buf = Buffer.from(await res.arrayBuffer());
  fs.writeFileSync(outPath, buf);
  return buf.length;
}

async function main() {
  const argLang = process.argv[2];
  const argAd = process.argv[3] ? parseInt(process.argv[3], 10) : null;
  const langs = argLang ? [argLang] : ['es', 'en'];

  for (const lang of langs) {
    const list = ADS[lang];
    if (!list) { console.error(`Lang desconocido: ${lang}`); continue; }
    const outDir = path.join('locucion-ads', lang);
    fs.mkdirSync(outDir, { recursive: true });
    console.log(`\n🎙️  Locución ${lang.toUpperCase()} → ${outDir}`);
    for (let i = 0; i < list.length; i++) {
      if (argAd && i + 1 !== argAd) continue;
      const [name, text] = list[i];
      const out = path.join(outDir, `${name}.mp3`);
      if (fs.existsSync(out) && fs.statSync(out).size > 5000) {
        console.log(`  ✓ ${name}.mp3 (ya existe, skip)`);
        continue;
      }
      process.stdout.write(`  · ${name}.mp3 ... `);
      try {
        const bytes = await tts(VOICES[lang], text, out);
        console.log(`OK (${Math.round(bytes / 1024)} KB)`);
      } catch (e) {
        console.log(`FAIL`);
        console.error(`    ${e.message}`);
      }
    }
  }
  console.log('\n✅ Listo. Locuciones en ./locucion-ads/');
}

main().catch((e) => { console.error(e); process.exit(1); });

