  /* SCENE 2 — CHAT EXCHANGES (3.5-7s) */
  .scene-chat {
    display: flex; flex-direction: column;
    justify-content: center; align-items: stretch;
    gap: 28px;
  }
  .ex {
    display: flex; flex-direction: column;
    gap: 16px;
    opacity: 0;
    transform: translateY(30px);
    transition: opacity 0.45s ease-out, transform 0.45s cubic-bezier(0.22,1.2,0.36,1);
  }
  .ex.show { opacity: 1; transform: translateY(0); }
  .ex-bubble {
    align-self: flex-end;
    max-width: 80%;
    padding: 24px 32px;
    background: var(--user-bub);
    border-radius: 28px;
    border-top-right-radius: 8px;
    font-size: 36px;
    font-weight: 500;
    line-height: 1.25;
    letter-spacing: -0.005em;
  }
  .ex-card {
    align-self: flex-start;
    background: var(--card);
    border-radius: 22px;
    padding: 22px 28px;
    display: flex;
    align-items: center;
    gap: 22px;
    box-shadow: 0 6px 18px rgba(0,0,0,0.06);
    border: 1px solid var(--line);
    opacity: 0;
    transform: translateX(-30px);
    transition: opacity 0.4s ease-out 0.25s, transform 0.4s cubic-bezier(0.22,1.2,0.36,1) 0.25s;
  }
  .ex.show .ex-card { opacity: 1; transform: translateX(0); }
  .ex-icon {
    width: 56px; height: 56px;
    border-radius: 16px;
    background: var(--accent-soft);
    color: var(--accent);
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
    font-size: 28px;
  }
  .ex-meta { display: flex; flex-direction: column; gap: 4px; flex: 1; }
  .ex-title { font-size: 30px; font-weight: 600; letter-spacing: -0.005em; }
  .ex-sub {
    font-size: 22px; font-weight: 500;
    color: var(--accent);
    display: flex; align-items: center; gap: 8px;
  }
  .ex-check {
    width: 26px; height: 26px;
    border-radius: 50%;
    background: var(--accent);
    color: #fff;
    display: flex; align-items: center; justify-content: center;
  }
  .ex-check svg { width: 16px; height: 16px; stroke: currentColor; stroke-width: 3.5; fill: none; stroke-linecap: round; stroke-linejoin: round; }

  /* SCENE 3 — 3 AIs (7-12.5s) */
  .scene-ais {
    display: flex; flex-direction: column;
    justify-content: center;
    gap: 36px;
  }
  .ai-row {
    background: var(--card);
    border-radius: 26px;
    padding: 32px;
    display: flex;
    align-items: center;
    gap: 28px;
    box-shadow: 0 10px 28px rgba(0,0,0,0.07);
    border: 1px solid var(--line);
    opacity: 0;
    transform: translateX(-40px);
    transition: opacity 0.5s ease-out, transform 0.55s cubic-bezier(0.22,1.2,0.36,1);
  }
  .ai-row.show { opacity: 1; transform: translateX(0); }
  .ai-avatar {
    width: 96px; height: 96px;
    border-radius: 24px;
    display: flex; align-items: center; justify-content: center;
    font-size: 44px; font-weight: 700;
    flex-shrink: 0;
  }
  .ai-row.claude .ai-avatar { background: var(--claude-bg); color: var(--claude); }
  .ai-row.codex  .ai-avatar { background: var(--codex-bg);  color: var(--codex);  }
  .ai-row.gemini .ai-avatar { background: var(--gemini-bg); color: var(--gemini); }
  .ai-meta { flex: 1; display: flex; flex-direction: column; gap: 6px; }
  .ai-name {
    font-size: 42px; font-weight: 700;
    letter-spacing: -0.015em;
  }
  .ai-action {
    font-size: 28px; font-weight: 500;
    color: var(--ink2);
  }
  .ai-snippet {
    margin-top: 14px;
    font-family: 'Geist', sans-serif;
    font-size: 22px;
    color: var(--ink2);
    font-weight: 500;
    line-height: 1.35;
    max-width: 30ch;
  }

  /* SCENE 4 — UNIFIED (12.5-20s) */
  .scene-unified {
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    text-align: center;
    gap: 60px;
  }
  .unified-title {
    font-size: 80px; font-weight: 700;
    line-height: 1.08;
    letter-spacing: -0.02em;
    max-width: 16ch;
  }
  .unified-title em {
    color: var(--accent);
    font-style: normal;
  }
  .unified-window {
    width: 100%;
    background: var(--card);
    border-radius: 28px;
    padding: 36px 40px;
    border: 1px solid var(--line);
    box-shadow: 0 18px 40px rgba(0,0,0,0.08);
    text-align: left;
  }
  .uw-header {
    display: flex; align-items: center;
    gap: 16px;
    padding-bottom: 22px;
    border-bottom: 1px solid var(--line);
  }
  .uw-dots { display: flex; gap: 8px; }
  .uw-dots i { width: 14px; height: 14px; border-radius: 50%; background: var(--line); display: block; }
  .uw-title { font-size: 24px; font-weight: 600; color: var(--ink2); letter-spacing: 0.04em; }
  .uw-badges {
    margin-left: auto;
    display: flex; gap: 10px;
  }
  .uw-badge {
    padding: 8px 18px;
    border-radius: 999px;
    font-size: 20px; font-weight: 600;
    display: flex; align-items: center; gap: 8px;
    transition: opacity 0.4s ease, filter 0.4s ease;
  }
  .uw-badge .dot { width: 10px; height: 10px; border-radius: 50%; }
  .uw-badge.claude { background: var(--claude-bg); color: var(--claude); }
  .uw-badge.claude .dot { background: var(--claude); }
  .uw-badge.codex  { background: var(--codex-bg);  color: var(--codex);  }
  .uw-badge.codex  .dot { background: var(--codex); }
  .uw-badge.gemini { background: var(--gemini-bg); color: var(--gemini); }
  .uw-badge.gemini .dot { background: var(--gemini); }
  .uw-body {
    padding-top: 26px;
    display: flex; flex-direction: column;
    gap: 18px;
  }
  .uw-line {
    display: flex; align-items: center;
    gap: 14px;
    font-size: 22px; font-weight: 500;
    color: var(--ink);
  }
  .uw-line .ic {
    width: 32px; height: 32px;
    border-radius: 50%;
    background: var(--accent);
    color: #fff;
    display: flex; align-items: center; justify-content: center;
  }
  .uw-line .ic svg { width: 18px; height: 18px; stroke: currentColor; stroke-width: 3; fill: none; stroke-linecap: round; stroke-linejoin: round; }

  /* SCENE 5 — CONTINUIDAD (handled in scene-unified by adding .dim to claude badge) */
  .uw-badge.dim { opacity: 0.35; filter: grayscale(1); }
  .uw-badge.glow {
    box-shadow: 0 0 0 4px color-mix(in oklch, var(--codex) 35%, transparent),
                0 0 28px color-mix(in oklch, var(--codex) 45%, transparent);
  }
  .continuity-caption {
    position: absolute;
    left: 80px; right: 80px;
    bottom: 240px;
    text-align: center;
    font-size: 42px;
    font-weight: 700;
    letter-spacing: -0.012em;
    line-height: 1.18;
    color: var(--ink);
    opacity: 0;
    transform: translateY(20px);
    transition: opacity 0.5s ease, transform 0.5s ease;
  }
  .continuity-caption.show { opacity: 1; transform: translateY(0); }

  /* SCENE 6 — BRAND CLOSE (24-30s) */
  .scene-brand {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    background: var(--bg);
    padding: 200px 80px;
  }
  .brand-logo {
    width: 168px; height: 168px;
    margin-bottom: 48px;
    filter: drop-shadow(0 12px 32px rgba(15, 157, 110, 0.22));
  }
  .brand-name {
    font-size: 64px; font-weight: 700;
    letter-spacing: -0.02em;
    color: var(--ink);
    margin-bottom: 44px;
  }
  .brand-tag {
    font-size: 64px;
    font-weight: 600;
    line-height: 1.12;
    letter-spacing: -0.022em;
    color: var(--ink);
    max-width: 18ch;
  }
  .brand-tag em {
    color: var(--accent);
    font-style: normal;
  }
  .brand-sub {
    margin-top: 26px;
    font-size: 38px;
    font-weight: 500;
    color: var(--ink2);
    letter-spacing: -0.01em;
  }
  .brand-url {
    margin-top: 56px;
    font-size: 30px;
    color: var(--ink2);
    letter-spacing: 0.08em;
  }
</style>
</head>
