// Genera la locución de los ads de 30s (Meta/TikTok/Reels) — ES + EN.
// Usa el mismo pipeline que generar-locucion.js (ElevenLabs, mismas voces).
// Uso:
//   export ELEVENLABS_API_KEY="..."
//   node scripts/generar-locucion-ads.js           # ES + EN
//   node scripts/generar-locucion-ads.js es        # solo ES
//   node scripts/generar-locucion-ads.js es 1      # solo ES, solo ad #1
// Output: ./locucion-ads/{es,en}/ad-NN-nombre.mp3
// Idempotente: skip-if-exists + retry con backoff exponencial.

const fs = require('fs');
const path = require('path');

const API_KEY = process.env.ELEVENLABS_API_KEY;
if (!API_KEY) { console.error('Falta ELEVENLABS_API_KEY'); process.exit(1); }

// Mismas voces del video corporativo — consistencia de marca.
const VOICES = {
  es: 'k7v2xzj8pZoayBVu9pvq', // Catalina - Sunny and Engaging (colombian)
  en: 'XZUXLIpE3dqJ9aCZUj2R', // Kristen - Upbeat social media (american)
};

// Settings más "punzantes" que el video largo — los ads necesitan urgencia.
// stability: 0.35 (más expresivo), style: 0.40 (más actuado).
const SETTINGS = { stability: 0.35, similarity_boost: 0.75, style: 0.40, use_speaker_boost: true };
const MODEL = 'eleven_multilingual_v2';

// Cada ad = un solo mp3 (la edición/timing se hace en el corte ffmpeg con cortes
// visuales sincronizados al audio). El guion va corrido con pausas naturales
// marcadas con "..." para que la voz respire en los beats clave.
// Orden de prioridad ESTRATÉGICO: WhatsApp primero (muestra > explica).
// Cada ad tiene una sola VO (la voz no narra el chat — el chat es silente
// + texto on-screen para preservar el "ahhh" moment de los primeros 4s).
// Resultado: locuciones cortas y punzantes que sirven como brand voice al cierre.
const ADS = {
  es: [
    // 15s · VO sobre cada bubble + cierre. Cuatro clips separados, posicionados en el corte.
    ['ad-01-line1',    '¿Seguimos con otra IA?'],
    ['ad-01-line2',    'Sí.'],
    ['ad-01-line3',    'Listo. Continúo donde quedó.'],
    ['ad-01-whatsapp', 'Las IAs se detienen. Tu negocio no. TerminalSync.'],

    // 30s · VO completa (~22s).
    ['ad-02-hero', [
      'La IA se detuvo.',
      'Y el trabajo también.',
      '',
      'Tienes que cambiar de IA.',
      'Explicarle todo otra vez.',
      'Esperar otra vez.',
      '',
      'Con TerminalSync cambias de IA',
      'sin perder el contexto.',
      '',
      'Tu proyecto sigue avanzando.',
      '',
      'Las IAs se detienen.',
      'Tu negocio no.',
      'TerminalSync.',
    ].join(' ')],

    // 30s · NIVEL 1 ad ("No necesitas ser programador") — 6 clips.
    ['ad-03-equipo-l1', 'No necesitas ser programador para trabajar con IA.'],
    ['ad-03-equipo-l2', 'Pídele una propuesta. Una campaña. Un análisis.'],
    ['ad-03-equipo-l3', 'Claude piensa. Codex construye. Gemini analiza.'],
    ['ad-03-equipo-l4', 'Todo desde un mismo lugar.'],
    ['ad-03-equipo-l5', 'Y si una IA se detiene, otra continúa el trabajo.'],
    ['ad-03-equipo-l6', 'TerminalSync. Tus IAs produciendo, y tú dirigiéndolas desde cualquier equipo.'],
  ],
  en: [
    // 15s · solo VO cierre.
    ['ad-01-whatsapp', "AIs stop. Your business doesn't. TerminalSync."],

    // 30s · VO completa.
    ['ad-02-hero', [
      'The AI stopped.',
      'And so did your work.',
      '',
      'You have to switch AIs.',
      'Explain everything again.',
      'Wait again.',
      '',
      'With TerminalSync you switch AIs',
      'without losing context.',
      '',
      'Your project keeps moving.',
      '',
      "AIs stop.",
      "Your business doesn't.",
      'TerminalSync.',
    ].join(' ')],

    // 30s · NIVEL 1 ad ("You don't need to be a developer") — 6 clips.
    ['ad-03-equipo-l1', "You don't need to be a developer to work with AI."],
    ['ad-03-equipo-l2', 'Ask for a proposal. A campaign. An analysis.'],
    ['ad-03-equipo-l3', 'Claude thinks. Codex builds. Gemini analyzes.'],
    ['ad-03-equipo-l4', 'All from one place.'],
    ['ad-03-equipo-l5', 'And if one AI stops, another keeps the work going.'],
    ['ad-03-equipo-l6', 'TerminalSync. Your AIs producing. You directing. From any device.'],
  ],
};

async function tts(voiceId, text, outPath, attempt = 1) {
  const url = `https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`;
  const body = JSON.stringify({ text, model_id: MODEL, voice_settings: SETTINGS });
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'xi-api-key': API_KEY,
      'Content-Type': 'application/json',
      Accept: 'audio/mpeg',
    },
    body,
  });
  if (!res.ok) {
    const err = await res.text();
    if (attempt < 4 && (res.status === 429 || res.status >= 500)) {
      const delay = 1000 * Math.pow(2, attempt);
      console.log(`  ⏳ ${res.status} — retry ${attempt}/3 en ${delay}ms`);
      await new Promise((r) => setTimeout(r, delay));
      return tts(voiceId, text, outPath, attempt + 1);
    }
    throw new Error(`ElevenLabs ${res.status}: ${err}`);
  }
  const buf = Buffer.from(await res.arrayBuffer());
  fs.writeFileSync(outPath, buf);
  return buf.length;
}

async function main() {
  const argLang = process.argv[2];
  const argAd = process.argv[3] ? parseInt(process.argv[3], 10) : null;
  const langs = argLang ? [argLang] : ['es', 'en'];

  for (const lang of langs) {
    const list = ADS[lang];
    if (!list) { console.error(`Lang desconocido: ${lang}`); continue; }
    const outDir = path.join('locucion-ads', lang);
    fs.mkdirSync(outDir, { recursive: true });
    console.log(`\n🎙️  Locución ${lang.toUpperCase()} → ${outDir}`);
    for (let i = 0; i < list.length; i++) {
      if (argAd && i + 1 !== argAd) continue;
      const [name, text] = list[i];
      const out = path.join(outDir, `${name}.mp3`);
      if (fs.existsSync(out) && fs.statSync(out).size > 5000) {
        console.log(`  ✓ ${name}.mp3 (ya existe, skip)`);
        continue;
      }
      process.stdout.write(`  · ${name}.mp3 ... `);
      try {
        const bytes = await tts(VOICES[lang], text, out);
        console.log(`OK (${Math.round(bytes / 1024)} KB)`);
      } catch (e) {
        console.log(`FAIL`);
        console.error(`    ${e.message}`);
      }
    }
  }
  console.log('\n✅ Listo. Locuciones en ./locucion-ads/');
}

main().catch((e) => { console.error(e); process.exit(1); });

