// Uso:
//   DEMO_BASE="file://$(pwd)/public/demos" node scripts/grabar-ad.mjs es
//   o con dev server:
//   node scripts/grabar-ad.mjs es
//
// Output: video/tomas-ads-<lang>/<demo>.mp4 (1080×1920 @30fps, libx264 CRF 18)

import { chromium } from 'playwright';
import { execSync } from 'node:child_process';
import fs from 'node:fs';

// nombre → segundos a grabar
const ADS = [
  ['demo-whatsapp-ad', 15],
  ['demo-equipo-ad',   30],
];

const LANG = process.argv[2] || 'es';
const BASE = process.env.DEMO_BASE || 'http://localhost:3000/demos';
const OUT = `video/tomas-ads-${LANG}`;
fs.mkdirSync(OUT, { recursive: true });

// Viewport vertical nativo de los ads.
const W = 1080, H = 1920;

for (const [name, secs] of ADS) {
  const mp4 = `${OUT}/${name}.mp4`;
  if (fs.existsSync(mp4)) {
    console.log('↷ skip (ya existe)', mp4);
    continue;
  }
  console.log('▶', name, secs + 's');
  const ctx = await chromium.launchPersistentContext('', {
    headless: true,
    viewport: { width: W, height: H },
    deviceScaleFactor: 1,
    recordVideo: { dir: OUT, size: { width: W, height: H } },
  });
  const page = ctx.pages()[0] || await ctx.newPage();
  page.on('pageerror', (e) => console.log('  ⚠ pageerror:', e.message.slice(0, 100)));
  await page.goto(`${BASE}/${name}.html?lang=${LANG}&embed=1`, { waitUntil: 'load' });
  await page.waitForTimeout(400);
  await page.waitForTimeout(secs * 1000);
  const video = page.video();
  await ctx.close();
  const webm = await video.path();
  execSync(
    `ffmpeg -y -i "${webm}" -vf "fps=30,scale=${W}:${H}:flags=lanczos" -c:v libx264 -pix_fmt yuv420p -crf 18 "${mp4}"`,
    { stdio: ['ignore', 'ignore', 'inherit'] },
  );
  fs.unlinkSync(webm);
  const sizeMB = (fs.statSync(mp4).size / 1024 / 1024).toFixed(1);
  console.log('  ✓', mp4, `(${sizeMB} MB)`);
}
console.log('\nTomas de ads en', OUT);
